package com.xxl.job.admin.controller.interceptor;

import org.junit.Before;
import org.junit.Test;
import org.mockito.Mockito;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockHttpServletResponse;
import org.springframework.web.servlet.ModelAndView;

import javax.servlet.http.Cookie;

import static org.mockito.Mockito.*;

public class CookieInterceptorTest {

    private CookieInterceptor cookieInterceptor;
    private MockHttpServletRequest request;
    private MockHttpServletResponse response;

    @Before
    public void setUp() {
        cookieInterceptor = new CookieInterceptor();
        request = new MockHttpServletRequest();
        response = new MockHttpServletResponse();
    }

    @Test
    public void testPostHandle_withCookies() throws Exception {
        // Arrange
        Cookie cookie1 = new Cookie("cookie1", "value1");
        Cookie cookie2 = new Cookie("cookie2", "value2");
        request.setCookies(cookie1, cookie2);
        ModelAndView modelAndView = new ModelAndView();

        // Act
        cookieInterceptor.postHandle(request, response, null, modelAndView);

        // Assert
        verify(modelAndView, times(1)).addObject(eq("cookieMap"), any());
    }

    @Test
    public void testPostHandle_withoutCookies() throws Exception {
        // Arrange
        ModelAndView modelAndView = new ModelAndView();

        // Act
        cookieInterceptor.postHandle(request, response, null, modelAndView);

        // Assert
        verify(modelAndView, times(1)).addObject(eq("cookieMap"), any());
    }

    @Test
    public void testPostHandle_withI18nUtil() throws Exception {
        // Arrange
        ModelAndView modelAndView = new ModelAndView();

        // Act
        cookieInterceptor.postHandle(request, response, null, modelAndView);

        // Assert
        verify(modelAndView, times(1)).addObject(eq("I18nUtil"), any());
    }

    @Test
    public void testPostHandle_withNullModelAndView() throws Exception {
        // Arrange
        ModelAndView modelAndView = null;

        // Act
        cookieInterceptor.postHandle(request, response, null, modelAndView);

        // Assert
        // No exceptions should be thrown, and no interactions with modelAndView should happen
    }
}

