package com.xxl.job.admin.core.util;

import org.junit.After;
import org.junit.Assert;
import org.junit.Before;
import org.junit.Test;

public class LocalCacheUtilTest {

    @Before
    public void before() {
        LocalCacheUtil.cleanTimeoutCache();
    }

    @After
    public void after() {
        LocalCacheUtil.cleanTimeoutCache();
    }

    @Test
    public void testGet() {
        String key = "testKey";
        String val = "testVal";
        boolean setResult = LocalCacheUtil.set(key, val, 1);
        Assert.assertTrue(setResult);

        Object getResult = LocalCacheUtil.get(key);
        Assert.assertEquals(val, getResult);
    }

    @Test
    public void testGet_NullKey() {
        Object getResult = LocalCacheUtil.get(null);
        Assert.assertNull(getResult);
    }

    @Test
    public void testGet_EmptyKey() {
        Object getResult = LocalCacheUtil.get("");
        Assert.assertNull(getResult);
    }

    @Test
    public void testGet_Timeout() {
        String key = "testKey";
        String val = "testVal";
        boolean setResult = LocalCacheUtil.set(key, val, 0.5);
        Assert.assertTrue(setResult);

        // sleep 1 second to let the cache timeout
        try {
            Thread.sleep(1000);
        } catch (InterruptedException e) {
            e.printStackTrace();
        }

        Object getResult = LocalCacheUtil.get(key);
        Assert.assertNull(getResult);
    }

    @Test
    public void testGet_NotExist() {
        String key = "notExistKey";
        Object getResult = LocalCacheUtil.get(key);
        Assert.assertNull(getResult);
    }
}

